from zipline.pipeline import Pipeline
from zipline.pipeline.factors import Returns, AverageDollarVolume
from zipline.api import attach_pipeline, pipeline_output, schedule_function, date_rules, time_rules, order_target_percent

def make_pipeline():
    momentum = Returns(window_length=21)
    dollar_volume = AverageDollarVolume(window_length=30)
    liquid = dollar_volume.top(500)

    return Pipeline(
        columns={'momentum': momentum},
        screen=liquid
    )

def initialize(context):
    attach_pipeline(make_pipeline(), 'factors')
    schedule_function(
        rebalance,
        date_rules.month_start(),
        time_rules.market_open(minutes=30)
    )

def before_trading_start(context, data):
    context.pipeline_data = pipeline_output('factors')

def rebalance(context, data):
    factors = context.pipeline_data
    longs = factors.nlargest(20, 'momentum').index
    for asset in longs:
        if data.can_trade(asset):
            order_target_percent(asset, 1.0 / len(longs))
